#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int S; scanf("%d",&S);
        long long *Q = (long long*)malloc(sizeof(long long)*S);
        for(int i=0;i<S;i++) scanf("%lld", &Q[i]);
        long long ans=0;
        for(int i=0;i<S;i++){
            int E; scanf("%d",&E);
            long long seasonSum=0;
            for(int j=0;j<E;j++){
                long long L; scanf("%lld", &L);
                seasonSum+=L;
            }
            ans += seasonSum - (long long)(E-1)*Q[i];
        }
        printf("%lld\n", ans);
        free(Q);
    }
    return 0;
}

